import React, { forwardRef } from 'react';
import type { ButtonProps } from './ButtonBase';
import { ButtonBase } from './ButtonBase';
import tuple from '../util/tuple';
import { omit } from '../util/omit';

import './style';
import { markAsDisabledableComp } from '../shared/markAsDisabledableComp';

const omitProps = tuple('children', 'type', 'size', 'endIcon', 'block', 'noMinWidth');

export const pickIconButtonProps = (props: Partial<ButtonProps>) => omit(props, omitProps);

/**
 * 支持原生`button`的所有事件和属性。
 * @public
 * @docgen
 * @privateRemarks
 * `extra-large`: 28px
 *   `large`: 24px
 *   `medium`: 20px
 *   `small`: 16px
 *   `extra-small`: 12px
 */
export interface IconButtonProps extends Omit<ButtonProps, (typeof omitProps)[number]> {
  /**
   * 设置按钮大小
   * @defaultValue `medium`
   */
  size?: ButtonProps['size'] | number;
}

const IconButton = /* #__PURE__*/ markAsDisabledableComp(
  forwardRef<any, IconButtonProps>((props, ref) => {
    const { style = {}, size } = props;
    let usedStyle = { ...style };
    let usedSize = size as ButtonProps['size'];
    if (typeof size === 'number') {
      usedStyle = {
        ...usedStyle,
        fontSize: `${props.size}px`,
      };
      usedSize = undefined;
    }

    return <ButtonBase {...props} size={usedSize} style={usedStyle} type="icon" ref={ref} />;
  }),
);
if (__DEV__) {
  IconButton.displayName = 'IconButton';
}

export { IconButton };
